mapper.select:
SELECT FROM team_invitation ti LEFT JOIN team_space ts ON ti.team_id = ts.id AND ts.is_deleted = 0 LEFT JOIN sys_user inviter ON ti.inviter_id = inviter.id AND inviter.is_deleted = 0 LEFT JOIN sys_account inviter_account ON ti.inviter_account_id = inviter_account.id AND inviter_account.status = 1 AND inviter_account.is_deleted = 0 LEFT JOIN sys_user invitee ON ti.invitee_id = invitee.id AND invitee.is_deleted = 0 LEFT JOIN sys_account invitee_account ON ti.invitee_account_id = invitee_account.id AND invitee_account.status = 1 AND invitee_account.is_deleted = 0 WHERE ti.team_id = #{teamId} AND ti.is_deleted = 0
AND ti.status = #{status}
ORDER BY ti.create_time DESC, ti.id DESC

mapper.update:
UPDATE team_invitation
SET status = #{expiredStatus},
    reason = #{reason},
    update_time = NOW()
WHERE team_id = #{teamId}
AND status = #{pendingStatus}
AND expire_at IS NOT NULL
AND expire_at <= #{now}
AND is_deleted = 0

