AND ti.status = #{status}
ORDER BY ti.create_time DESC, ti.id DESC

mapper.update:
UPDATE team_invitation
SET status = #{expiredStatus},
    reason = #{reason},
    update_time = NOW()
WHERE invitee_account_id = #{inviteeAccountId}
AND status = #{pendingStatus}
AND expire_at IS NOT NULL
AND expire_at <= #{now}
AND is_deleted = 0

