SELECT * FROM team_invitation
WHERE id = #{invitationId}
AND team_id = #{teamId}
AND status = #{pendingStatus}
AND is_deleted = 0
LIMIT 1

SELECT * FROM team_invitation
WHERE team_id = #{teamId}
AND status = #{pendingStatus}
AND is_deleted = 0
ORDER BY id ASC

SELECT COUNT(1) > 0 FROM team_invitation
WHERE team_id = #{teamId}
AND invitee_account_id = #{inviteeAccountId}
AND status = #{pendingStatus}
AND expire_at > #{now}
AND is_deleted = 0

SELECT COUNT(1) > 0 FROM team_member
WHERE team_id = #{teamId}
AND account_id = #{accountId}
AND status = #{activeStatus}
AND is_deleted = 0
